const req = $input.first().json;
return [{
  json: {
    client_id: req.body.client_id,
    timestamp: req.headers['x-caiac-timestamp'],
    signature: req.headers['x-caiac-signature'],
    token: (req.headers.authorization || '').replace(/^Bearer\s+/i, ''),
    webhook_secret: req.headers['x-webhook-secret'] || ''
  }
}];

const session = $input.first().json;

if (session.is_caiac_staff !== true) {
  throw new Error('Insufficient permissions: is_caiac_staff required');
}

const body = $('Receive Ingest Request').first().json.body;

const validDocumentRoles = ['public', 'staff', 'admin', 'owner'];
if (!body.role || !validDocumentRoles.includes(body.role)) {
  throw new Error(`Invalid document role: "${body.role}". Must be one of: ${validDocumentRoles.join(', ')}`);
}

return [{
  json: {
    user_id: session.user_id,
    is_caiac_staff: true,
    client_slug: body.client_id,
    filename: body.filename,
    role: body.role,
    file_b64: body.file_base64
  }
}];

const session = $('Receive Ingest Request').item.json.body;
const file_b64 = session.file_base64;
const fileSizeBytes = Math.round(file_b64.length * 0.75);
const estimatedPages = Math.round(fileSizeBytes / 75000);
const fileSizeMB = (fileSizeBytes / 1048576).toFixed(1);
if (estimatedPages > 100) {
  throw new Error(
    `"${session.filename}" is ~${estimatedPages} pages (${fileSizeMB} MB) — exceeds the 100-page limit for Docling. Split into ≤100-page parts or use /opt/caiac/ingest.py directly.`
  );
}
return [{ json: { ...session, estimated_pages: estimatedPages } }];

const body = $('Receive Ingest Request').first().json.body;
const content = Buffer.from(body.file_base64, 'base64').toString('utf8');

const lines = content.split('\n');
const sections = [];
let current = '';

for (const line of lines) {
  if (/^## /.test(line)) {
    if (current.trim()) sections.push(current.trim());
    current = line + '\n';
  } else {
    current += line + '\n';
  }
}
if (current.trim()) sections.push(current.trim());

const chunks = sections.length > 1 ? sections.map(s => ({ text: s })) : [{ text: content }];
return [{ json: { chunks } }];

const doclingResult = $input.first().json;
const session = $('Check Token Valid').first().json;

const rawChunks = doclingResult.chunks || [];
if (!rawChunks.length) {
  throw new Error('No chunks returned for ' + (session.filename || 'unknown'));
}

const getText = c => typeof c === 'string' ? c : (c.text || c.content || '');

const sectionBoundaries = [];
rawChunks.forEach((c, i) => {
  if (/^##\s+/m.test(getText(c))) {
    sectionBoundaries.push(i);
  }
});

function getSectionText(chunkIdx) {
  if (sectionBoundaries.length === 0) return null;
  let start = 0;
  let end = rawChunks.length;
  for (let i = 0; i < sectionBoundaries.length; i++) {
    if (sectionBoundaries[i] <= chunkIdx) {
      start = sectionBoundaries[i];
      end = (i + 1 < sectionBoundaries.length) ? sectionBoundaries[i + 1] : rawChunks.length;
    }
  }
  return rawChunks.slice(start, end).map(getText).filter(Boolean).join('\n\n');
}

return rawChunks
  .map((c, i) => {
    const text = getText(c);
    if (!text.trim()) return null;
    const sectionText = getSectionText(i);
    return { json: {
      text,
      section_text: sectionText && sectionText !== text ? sectionText : null,
      chunk_index: i,
      chunk_count: rawChunks.length,
      filename: session.filename,
      client_id: session.client_id,
      client_slug: session.client_slug,
      role: session.role,
      user_id: session.user_id,
    }};
  })
  .filter(Boolean);

const embeddingItems = $input.all();
const chunkItems = $('Embed and Prepare Points').all();

if (embeddingItems.length !== chunkItems.length) {
  throw new Error(`Embedding count (${embeddingItems.length}) !== chunk count (${chunkItems.length})`);
}

const points = embeddingItems.map((item, i) => {
  const embedding = item.json.embedding;
  if (!embedding || !embedding.length) {
    throw new Error('Ollama returned empty embedding for chunk ' + i);
  }
  const chunk = chunkItems[i].json;
  const pointId = Math.abs((Date.now() + i * 997) % 2147483647);
  return {
    id: pointId,
    vector: embedding,
    payload: {
      text: chunk.text,
      section_text: chunk.section_text || null,
      source: chunk.filename,
      client_id: chunk.client_slug,
      type: 'document',
      role: chunk.role,
      chunk_index: chunk.chunk_index,
    }
  };
});

const meta = chunkItems[0].json;
return [{ json: {
  points,
  count: points.length,
  client_slug: meta.client_slug,
  client_id: meta.client_id,
  filename: meta.filename,
  role: meta.role,
  user_id: meta.user_id,
} }];
